                    @case ('incorrect') { Incorrect! }
                    @case ('time-up') { Time's up! }
                }
            </p>
        }
    }

    @case ('game-over') {
      <div class="text-center text-white">
        <h2 class="text-3xl font-bold mb-4">Game Over!</h2>
        <p class="text-xl">Your Score: {{ score() }}</p>
        <button class="mt-4 px-6 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600 transition-all duration-300" (click)="gameState.set('level-select')">Play Again</button>
      </div>
    }
  }
</div>
