  mathService = inject(MathService);
  speechService = inject(SpeechRecognitionService);

  levels = signal<Level[]>([]);

  gameState = signal<GameState>('level-select');
  selectedLevel = signal<Level | null>(null);
  problems = signal<Problem[]>([]);
  currentProblemIndex = signal(0);
  score = signal(0);

  timeLeft = signal(TIME_PER_QUESTION);
  feedback = signal<Feedback>(null);

  private timerInterval: any = null;
  private speechSubscription: Subscription;

  currentProblem = computed(() => {
    const p = this.problems();
    const i = this.currentProblemIndex();
    return p.length > i ? p[i] : null;
  });

  timerProgress = computed(() => {
    return (this.timeLeft() / TIME_PER_QUESTION) * 100;
  });

