        const state = this.gameState();
        if (state === 'playing') {
            this.startQuestion();
        }

        onCleanup(() => {
            this.clearTimer();
            if (this.speechService.isListening()) {
                this.speechService.stopListening();
            }
        });
    }, { allowSignalWrites: true });
  }

